var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"생각이 정리되질 않는군. 그자의 정체는 고사하고, 내게 호의적인 이유를 모르겠어.","JPN":"考えがまとまらない。あの者の正体はおろか、私に好意的な理由がわからない。","ENG":"I can't seem to gather my thoughts. I don't even know who she is, let alone why she's being so friendly towards me.","TWN":"無法整理思緒。別說她的身分了，我連她為何向我釋出善意都不清楚。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무엇보다…….","JPN":"何より……","ENG":"More importantly...","TWN":"最重要的是……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"늦지 않아서 다행이에요, <color=#ffd34c>에스텔</color>.","JPN":"間に合って良かったです、<color=#ffd34c>エステル</color>。","ENG":"Good thing I wasn't too late, <color=#ffd34c>Esther</color>.","TWN":"幸好沒來晚，艾斯特。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오랜만… 아니, 여기서는 처음 뵙는다고 말하는 편이 나으려나요?","JPN":"お久しぶり……いえ、ここでははじめましてと言ったほうがいいかしら？","ENG":"Long time no see– Or maybe, \\"Nice to meet you\\" fits better in this context?","TWN":"好久不見…啊，還是說在這裡應該說初次見面呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"미몽에 홀려 간밤에 꾸는 꿈을 현실과 착란하시면 곤란합니다.","JPN":"夢まぼろしの世界と現実を勘違いしてはいけません。","ENG":"It's troubling when dreams blur into reality just because they feel vivid.","TWN":"被虛幻迷惑，若將昨夜的夢境與現實混淆可就麻煩了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L11_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"버고 소드를 뽑은 이래, <color=#ffd34c>이런 경험</color>은 숱하게 하셨을 텐데요?","JPN":"ヴァルゴソードを抜いて以来、<color=#ffd34c>こういう経験</color>を何度もしたはずです。","ENG":"You've drawn the Virgo Sword, haven't you? You must be used to strange <color=#ffd34c>experiences</color> by now.","TWN":"拔出布林加夫之劍後，你應該經歷過很多這樣的事情吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그자는 단원들과 알렌 경을 제외하면 알 수 없는 내용까지 알고 있었다.","JPN":"あの者は団員たちやアレン卿を除けば誰も知らないはずの内容まで知っていた。","ENG":"She knew things only the knights and Sir Allen could possibly know.","TWN":"那個人知道的事情，除了團員和艾倫卿之外，其他人都無法知曉。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하다못해 내게 접근한 이유라도 알면 좋겠는데, 전혀 짐작가는 게 없어.","JPN":"私に近づいてきた理由だけでもわかればいいのだが、まったく見当がつかない。","ENG":"If I could at least figure out why she approached me, that would be nice. But I don't have the slightest idea.","TWN":"哪怕只是知道你接近我的理由也好，但我完全沒有頭緒。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다, 에스텔. 약속대로 검의 수리를 끝마쳤습니다.","JPN":"お待たせしました、エステル。約束どおり、剣の修理が終わりました。","ENG":"You've waited long enough, Esther. As promised, your sword is fully repaired.","TWN":"久等了，艾斯特。按照約定，我已經完成了劍的修理。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"손에 맞는지 한번 들어 보시지요.","JPN":"手に馴染むか一度持ってみてください。","ENG":"Go ahead and test how it feels in your hand.","TWN":"拿起來看看是否順手吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 문제라도 있으십니까?","JPN":"どうしましたか？","ENG":"Is something wrong?","TWN":"有什麼問題嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아뇨. 순전히 놀랐을 뿐입니다. 이건 굉장히 좋은 검이군요.","JPN":"いいえ。純粋に驚いただけです。これは本当に素晴らしい剣ですね。","ENG":"No. I'm just surprised, that's all. This is an excellent sword.","TWN":"不。這只是讓我感到驚訝而已。這是一把非常好的劍。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"겉보기에는 큰 변화가 없는데, 조금 과장하여 별의 무구와 비견될 정도입니다.","JPN":"見た目は大して変わらないのに、少し大げさに言えば、星の武具と並ぶほどの出来栄えです。","ENG":"It may not look much different, but perhaps with a bit of an exaggeration, I'd say that it could almost rival a Star Armament.","TWN":"表面上看似沒有太大變化，但稍微誇張一點的話，可以與星之武具相媲美。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 제입으로 말하기 뭐하지만 무구를 다루는 데는 제법 조예가 깊은 편입니다.","JPN":"ふふ。自分で言うのも恥ずかしいのですが、武具の扱いにおいてはかなり造詣の深い方でして。","ENG":"Haha. It might sound boastful, but I have some experience when it comes to working with Armaments.","TWN":"呵呵。雖然不好意思自己說，但我在使用武器方面頗有造詣。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 제국에서도 가히 최고라 일컬어지죠.","JPN":"ええ。帝国でも最高と言われております。","ENG":"Yes, even within the Empire, I'm considered one of the best.","TWN":"是的。在帝國中也被稱為最頂尖的。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"뭐하다고 한 것 치고는 제법 말씀하시는군요.","JPN":"恥ずかしいというわりには平然と自慢をしているようですが。","ENG":"You sure don't sound modest for someone who claimed to be humble.","TWN":"看你說得那麼輕鬆，沒想到手藝不錯。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"버밍엄 백작님. 분부하신 대로 평기사들을 집결시켰습니다.","JPN":"バーミンガム伯爵。ご指示のとおり、平騎士たちを集めました。","ENG":"Countess Birmingham. As ordered, all standard knights have assembled.","TWN":"伯明罕伯爵大人。按照你的指示，已經集結了平民騎士。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다행이군요. 마침 이쪽의 준비도 끝난 참입니다.","JPN":"良かったわ。ちょうどこちらも準備が整ったところです。","ENG":"Excellent. We've just finished preparations on our side as well.","TWN":"那就好。正好這邊的準備也完成了。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"준비? 기사들의 훈련 일정이라도 잡혀 있었던 겁니까?","JPN":"準備？　騎士の訓練の予定でもあるのですか？","ENG":"Preparations? Is there a training session scheduled?","TWN":"準備？是要訓練騎士嗎？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 오늘은 단체 훈련이 있는 날입니다.","JPN":"ええ。本日は全体訓練がある日なのです。","ENG":"Indeed. Today is group training day.","TWN":"是的，今天是集體訓練的日子。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"연무장에 있는 전원이 마지막 한 사람이 남을 때까지 계속하여 싸우는 것이지요.","JPN":"訓練場にいる全員が最後の一人になるまで戦い続けます。","ENG":"Everyone in the training hall will fight until only one remains standing.","TWN":"演武場上的所有人將一直戰鬥，直到最後一個人倒下為止。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건 꽤나 과격한 방식이군요.","JPN":"それはなかなか過激なやり方ですね。","ENG":"That's a rather intense method.","TWN":"方式還真激烈。"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"잠깐, 전원이라고?","JPN":"待ってください、全員？","ENG":"Wait, everyone?","TWN":"等等，所有人？"},"stage":{"bg":"CORRIDOR_10","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"咳？！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"갑자기 이게 무슨 짓입니까?","JPN":"いきなりどういうことですか？","ENG":"What is the meaning of this all of a sudden?!","TWN":"你突然這是在幹什麼？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"무르군. 세상 어느 괴수가 공격 전에 알려주겠나?","JPN":"甘いな。どの怪獣も攻撃前に合図などしてくれない。","ENG":"Weak. What kind of monster warns you before striking?","TWN":"太天真了。世上哪有怪物會在攻擊前通知你的？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRIDE_NULL_NULL","text":{"KOREA":"연무장에 온 이상 이 정도는 각오했어야지.","JPN":"訓練場に来た以上、これくらいは覚悟しておくべきだろう。","ENG":"Once you've entered the training grounds, this sort of thing is to be expected.","TWN":"既然來到演武場，就應該做好這樣的心理準備。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"전 부인께서 부르신 겁니다!","JPN":"私は夫人に呼ばれて来ただけです！","ENG":"I'm here because she invited me!","TWN":"是夫人叫我來的！"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"KNIGHT_PRIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"검을 시험하는데 베는 것 이외에 다른 방도가 있겠습니까?","JPN":"剣を試すのに斬る以外の方法がありますか？","ENG":"And how else should one test a sword but by cutting?","TWN":"測試劍術當然要砍來砍去的，不然要怎麼測試？"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"연무장에서 피를 보는 일은 없을 테니, 경께서는 안심하고 검을 시험해 보시지요.","JPN":"訓練場で血を見ることはありませんから、卿は安心して剣をお試しください。","ENG":"There won't be any real bloodshed in the training hall, so feel free to test the blade to your heart's content.","TWN":"在演武場上不會見血，你可以放心地試試劍術。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게 무슨…….","JPN":"それはどういう……","ENG":"What...?","TWN":"那是什麼……"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모자람이 많으나 기사로서의 도를 갖춘 이들이니 관용을 베풀 필요는 없습니다.","JPN":"実力で劣っていたとしても、騎士としての道理をわきまえている者たちですので手加減はいりません。","ENG":"They may be lacking in some respects, but as knights, they understand restraint. There's no need to hold back.","TWN":"雖然有很多不足，但他們已經具備了騎士精神，所以不需要手下留情。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부디, 백작령의 기사들에게 한 수 가르쳐 주시길.","JPN":"どうか、伯爵領の騎士にお手本を。","ENG":"Please, do teach these knights a thing or two.","TWN":"請你教訓一下伯爵領地的騎士們吧。"},"stage":{"bg":"CORRIDOR_10","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};